import json, sys, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")

    # Check if this is a git commit command
    if "git" not in command:
        return 0

    # Parse command parts to identify git commit
    parts = command.split()
    if len(parts) < 2 or parts[0] != "git" or parts[1] != "commit":
        return 0

    # Run lint check before allowing commit
    try:
        result = subprocess.run(
            ["pnpm", "lint"],
            cwd=os.getcwd(),
            capture_output=True,
            timeout=30
        )
        if result.returncode != 0:
            msg = "BLOCKING: pnpm lint failed. Fix linting errors before committing."
            print(msg, file=sys.stderr)
            return 2
    except Exception:
        # If lint check fails (e.g., pnpm not available), allow commit to proceed
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only act on Edit tool
    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")

    # Only act on .py files
    if not file_path.endswith(".py"):
        return 0

    # Check file exists
    if not os.path.exists(file_path):
        return 0

    # Run ruff format
    try:
        result = subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            text=True,
            timeout=10
        )

        if result.returncode == 0:
            # Formatting succeeded
            if "reformatted" in result.stdout or "unchanged" in result.stdout:
                print(f"REQUIRED FOLLOW-UP: Auto-formatted {file_path} per project ruff config", file=sys.stderr)
                print(result.stdout.strip(), file=sys.stderr)
        else:
            # ruff format failed
            print(f"REQUIRED FOLLOW-UP: ruff format failed on {file_path}", file=sys.stderr)
            if result.stderr:
                print(result.stderr.strip(), file=sys.stderr)

    except subprocess.TimeoutExpired:
        print(f"REQUIRED FOLLOW-UP: ruff format timeout on {file_path}", file=sys.stderr)
    except FileNotFoundError:
        # ruff not installed, silently skip
        pass
    except Exception as e:
        print(f"REQUIRED FOLLOW-UP: ruff format error on {file_path}: {e}", file=sys.stderr)

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import subprocess
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith((".ts", ".tsx")):
        return 0

    new_string = inp.get("new_string", "")
    old_string = inp.get("old_string", "")

    # Extract exported identifier names from both old and new content
    pattern = r'export\s+(?:const|function|type|class|interface)\s+([A-Za-z_$][A-Za-z0-9_$]*)'
    new_exports = set(re.findall(pattern, new_string))
    old_exports = set(re.findall(pattern, old_string))

    # Check for changed/added/removed exports
    changed_exports = old_exports.symmetric_difference(new_exports) | new_exports

    if not changed_exports:
        return 0

    # For each export, grep for references across the codebase
    findings = {}
    for name in sorted(changed_exports):
        try:
            result = subprocess.run(
                ["grep", "-r", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx",
                 f"\\b{name}\\b"],
                capture_output=True,
                text=True,
                timeout=5,
                cwd="."
            )
            if result.stdout:
                refs = [line for line in result.stdout.strip().split('\n') if line]
                findings[name] = len(refs)
        except Exception:
            pass

    if findings:
        lines = ["REQUIRED FOLLOW-UP: Update all references to these changed exports:"]
        for name, count in sorted(findings.items()):
            lines.append(f"  {name}: {count} reference(s)")
        msg = "\n".join(lines)
        print(msg, file=sys.stderr)

    return 0

if __name__ == "__main__":
    sys.exit(main())

