import json
import sys
import re


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Extract content to check based on tool
    content = ""
    if tool == "Edit":
        content = inp.get("new_string", "")
    elif tool == "Write":
        content = inp.get("content", "")
    else:
        return 0

    # High-confidence patterns for common secrets
    secret_patterns = [
        r'sk-[A-Za-z0-9\-]{20,}',           # OpenAI API keys (sk-proj-...)
        r'pk_(live|test)_[A-Za-z0-9]{20,}', # Stripe keys
        r'ghp_[A-Za-z0-9]{36,}',            # GitHub Personal Access Tokens
        r'AKIA[0-9A-Z]{16}',                # AWS Access Key IDs
        r'(?:api_?key|apikey)\s*[:=]\s*["\']sk-',  # API key assignment with OpenAI format
    ]

    for pattern in secret_patterns:
        if re.search(pattern, content, re.IGNORECASE):
            msg = "BLOCKING: Hardcoded secret detected. REQUIRED FOLLOW-UP: Use process.env for secrets, not source files."
            print(msg, file=sys.stderr)
            return 2

    return 0


if __name__ == "__main__":
    sys.exit(main())

