#!/usr/bin/env python3
import json, sys, subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Try flake8 first (catches undefined names F821, syntax errors E999, etc.)
    try:
        result = subprocess.run(
            ["flake8", "--select=F821,E999,F", file_path],
            capture_output=True,
            text=True,
            timeout=3
        )
        if result.returncode != 0 and result.stdout.strip():
            print(f"flake8 issues in {file_path}:\n{result.stdout}", file=sys.stderr)
            return 2
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass

    # Fall back to syntax check with py_compile
    try:
        result = subprocess.run(
            [sys.executable, "-m", "py_compile", file_path],
            capture_output=True,
            text=True,
            timeout=2
        )
        if result.returncode != 0:
            print(f"Python syntax error in {file_path}:\n{result.stderr}", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
